    set({ isCompacting: compacting });
  },

  // Computed property: check if currently in plan mode
  isPlanMode: (): boolean => {
    return get().permissionMode === "plan";
  },

  clearSession: (): void => {
    set({
      sessionId: null,
      totalCost: 0,
      tokenCount: {
        input: 0,
        output: 0,
      },
      permissionMode: "default",
      isCompacting: false,
    });
  },
});

/**
 * Type definitions for Zustand store
 * Central state management for TUI application
 */

// Content block types (matching Anthropic SDK structure)
export interface TextContent {
  type: "text";
  text: string;
}

export interface ToolUseContent {
  type: "tool_use";
  id: string;
  name: string;
  input: Record<string, unknown>;
}

export interface ToolResultContent {
  type: "tool_result";
  tool_use_id: string;
  content: string;
  is_error?: boolean;
}

export type ContentBlock = TextContent | ToolUseContent | ToolResultContent;

// Message interface
export interface Message {
  id: string;
  role: "user" | "assistant" | "system";
  content: ContentBlock[];
  partial: boolean;
  timestamp: number;
}

// Agent interface with tree structure
export interface Agent {
  id: string;
  parentId: string | null;
  model: string;
  tier: "haiku" | "sonnet" | "opus";
  status: "spawning" | "running" | "complete" | "error";
  description?: string;
  startTime: number;
  endTime?: number;
  tokenUsage?: {
    input: number;
    output: number;
  };
}

// Session data (matches Go format exactly)
export interface SessionData {
  id: string;
  name?: string;
  created_at: string; // ISO8601
  last_used: string; // ISO8601
  cost: number;
  tool_calls: number;
}

// Token count structure
export interface TokenCount {
  input: number;
  output: number;
}

// Messages slice
export interface MessagesSlice {
  messages: Message[];
  addMessage: (msg: Omit<Message, "id" | "timestamp">) => void;
  updateLastMessage: (content: ContentBlock[]) => void;
  clearMessages: () => void;
}

// Agents slice
export interface AgentsSlice {
  agents: Record<string, Agent>;
  selectedAgentId: string | null;
  rootAgentId: string | null;
  addAgent: (agent: Omit<Agent, "startTime">) => void;
  updateAgent: (id: string, data: Partial<Agent>) => void;
  selectAgent: (id: string | null) => void;
  getAgentChildren: (id: string) => Agent[];
  clearAgents: () => void;
}

// Session slice (Go format compatible)
export interface SessionSlice {
  sessionId: string | null;
  totalCost: number;
  tokenCount: TokenCount;
  permissionMode: string;
  isCompacting: boolean;
  updateSession: (data: Partial<SessionData>) => void;
  incrementCost: (cost: number) => void;
  addTokens: (tokens: Partial<TokenCount>) => void;
  setPermissionMode: (mode: string) => void;
  setCompacting: (compacting: boolean) => void;
  isPlanMode: () => boolean;
  clearSession: () => void;
}

// UI slice
export interface UISlice {
  streaming: boolean;
  focusedPanel: "claude" | "agents";
  setStreaming: (streaming: boolean) => void;
  setFocusedPanel: (panel: "claude" | "agents") => void;
}

// Input history slice (ephemeral - not persisted)
export interface InputSlice {
  inputHistory: string[]; // Max 100 entries
  inputHistoryIndex: number; // -1 = not navigating, 0+ = position
  addToHistory: (input: string) => void;
  navigateHistory: (direction: "up" | "down") => string | null;
  resetHistoryIndex: () => void;
  clearHistory: () => void;
}

// Modal slice (ephemeral - not persisted)
export interface ModalSlice {
  modalQueue: Array<{
    id: string;
    type: "ask" | "confirm" | "input" | "select";
    payload: unknown;
    resolve: (response: ModalResponse) => void;
    reject: (error: Error) => void;
    timeout?: number;
    timeoutId?: NodeJS.Timeout;
  }>;
  enqueue: <T>(
    request: Omit<
      {
        id: string;
        type: "ask" | "confirm" | "input" | "select";
        payload: T;
        resolve: (response: ModalResponse) => void;
        reject: (error: Error) => void;
        timeout?: number;
        timeoutId?: NodeJS.Timeout;
      },
      "id" | "resolve" | "reject" | "timeoutId"
    >
  ) => Promise<ModalResponse>;
  dequeue: (id: string, response: ModalResponse) => void;
  cancel: (id: string) => void;
}

export type ModalResponse =
  | { type: "ask"; value: string }
  | { type: "confirm"; confirmed: boolean; cancelled: boolean }
  | { type: "input"; value: string }
  | { type: "select"; selected: string; index: number };

// Import telemetry types
import type { TelemetrySlice } from "./slices/telemetry.js";
export type { TelemetrySlice, RoutingDecision, Handoff, SharpEdge } from "./slices/telemetry.js";

// Combined store type
export type Store = MessagesSlice &
  AgentsSlice &
  SessionSlice &
  UISlice &
  InputSlice &
  ModalSlice &
  TelemetrySlice;

/**
 * Telemetry store slice - manages real-time telemetry data from Go hooks
 * Tracks routing decisions, session handoffs, and sharp edges
 */

import type { StateCreator } from "zustand";
import type { Store } from "../types.js";

// Routing decision from gogent-validate
export interface RoutingDecision {
  timestamp: string;
  agent: string;
  model: string;
  subagent_type: string;
  tier: string;
  cost_estimate: number;
  recommended_tier?: string;
}

// Session handoff from gogent-archive
export interface Handoff {
  timestamp: string;
  session_id: string;
  summary: string;
  pending_tasks: string[];
  sharp_edges: string[];
  context: Record<string, unknown>;
}

// Sharp edge from gogent-sharp-edge
export interface SharpEdge {
  timestamp: string;
  pattern: string;
  file: string;
  description: string;
  failure_count: number;
}

export interface TelemetrySlice {
  routingDecisions: RoutingDecision[];
  lastHandoff: Handoff | null;
  sharpEdges: SharpEdge[];
  totalRoutingCost: number;
  updateTelemetry: (key: "routingDecisions" | "handoffs" | "sharpEdges", data: unknown) => void;
  clearTelemetry: () => void;
}

export const createTelemetrySlice: StateCreator<
  Store,
  [],
  [],
  TelemetrySlice
> = (set, _get) => ({
  routingDecisions: [],
  lastHandoff: null,
  sharpEdges: [],
  totalRoutingCost: 0,

  updateTelemetry: (key, data) => {
    set((state: Store) => {
      switch (key) {
        case "routingDecisions": {
          const decision = data as RoutingDecision;
          return {
            routingDecisions: [...state.routingDecisions, decision],
            totalRoutingCost: state.totalRoutingCost + (decision.cost_estimate || 0),
          };
        }
        case "handoffs": {
          const handoff = data as Handoff;
          return {
            lastHandoff: handoff,
          };
        }
        case "sharpEdges": {
          const edge = data as SharpEdge;
          return {
            sharpEdges: [...state.sharpEdges, edge],
          };
        }
        default:
          return state;
      }
    });
  },

  clearTelemetry: () => {
    set({
      routingDecisions: [],
      lastHandoff: null,
      sharpEdges: [],
      totalRoutingCost: 0,
    });
  },
});

/**
 * Agents slice for Zustand store
 * Manages agent tree with parent/child relationships
 */

import type { StateCreator } from "zustand";
import type { Store, AgentsSlice, Agent } from "../types.js";

export const createAgentsSlice: StateCreator<Store, [], [], AgentsSlice> = (
  set,
  get
) => ({
  agents: {},
  selectedAgentId: null,
  rootAgentId: null,

  addAgent: (agent): void => {
    set((state) => {
      const newAgent: Agent = {
        ...agent,
        startTime: Date.now(),
      };

      const agents = { ...state.agents };
      agents[newAgent.id] = newAgent;

      // Track root agent (first agent with no parent)
      const rootAgentId =
        state.rootAgentId || (agent.parentId === null ? newAgent.id : null);

      return {
        agents,
        rootAgentId,
      };
    });
  },

  updateAgent: (id, data): void => {
    set((state) => {
      const agent = state.agents[id];
      if (!agent) {
        return state;
      }

      const agents = { ...state.agents };
      agents[id] = { ...agent, ...data };

      return { agents };
    });
  },

  selectAgent: (id): void => {
    set({ selectedAgentId: id });
  },

  getAgentChildren: (id): Agent[] => {
    const agents = get().agents;

    // Null safety: return empty array if parent doesn't exist
    if (!(id in agents)) {
      return [];
    }

    const children: Agent[] = [];

    Object.values(agents).forEach((agent) => {
      if (agent.parentId === id) {
        children.push(agent);
      }
    });

    return children;
  },

  clearAgents: (): void => {
    set({
      agents: {},
      selectedAgentId: null,
      rootAgentId: null,
    });
  },
});

/**
 * Messages slice for Zustand store
 * Handles conversation message state with partial update support
 */

import type { StateCreator } from "zustand";
import type { Store, MessagesSlice } from "../types.js";
import { nanoid } from "nanoid";

export const createMessagesSlice: StateCreator<
  Store,
  [],
  [],
  MessagesSlice
> = (set) => ({
  messages: [],

  addMessage: (msg): void => {
    set((state) => ({
      messages: [
        ...state.messages,
        {
          ...msg,
          id: nanoid(),
          timestamp: Date.now(),
        },
      ],
    }));
  },

  updateLastMessage: (content): void => {
    set((state) => {
      if (state.messages.length === 0) {
        return state;
      }

      // Update in-place to prevent flicker
      const messages = [...state.messages];
      const lastIndex = messages.length - 1;
      const lastMessage = messages[lastIndex];

      if (!lastMessage) {
        return state;
      }

      messages[lastIndex] = {
        ...lastMessage,
        content,
        partial: false, // Mark as complete when updating
      };

      return { messages };
    });
  },

  clearMessages: (): void => {
    set({ messages: [] });
  },
});

/**
 * Tests for useSession hook
 * Verifies session persistence, ID generation, and error recovery
 */

import { describe, it, expect, beforeEach, afterEach, vi } from "vitest";
import { promises as fs } from "fs";
import { join } from "path";
import { tmpdir } from "os";
import {
  useSession,
  listSessions,
  loadSession,
  saveSession,
  deleteSession,
} from "../../src/hooks/useSession.js";
import type { SessionData } from "../../src/store/types.js";

// Mock HOME directory for testing
const TEST_HOME = join(tmpdir(), `gofortress-session-test-${Date.now()}`);
const TEST_SESSION_DIR = join(TEST_HOME, ".claude", "sessions");

describe("useSession", () => {
  beforeEach(async () => {
    // Set test HOME
    process.env["HOME"] = TEST_HOME;

    // Create session directory
    await fs.mkdir(TEST_SESSION_DIR, { recursive: true });
  });

  afterEach(async () => {
    // Clean up test directory
    try {
      await fs.rm(TEST_HOME, { recursive: true, force: true });
    } catch (error) {
      // Ignore cleanup errors
    }

    // Restore original HOME
    delete process.env["HOME"];
  });

  /**
   * Helper to create a valid session object
   */
  function createSession(overrides: Partial<SessionData> = {}): SessionData {
    return {
      id: `test-session-${Date.now()}-${Math.random()}`,
      name: "Test Session",
      created_at: new Date().toISOString(),
      last_used: new Date().toISOString(),
      cost: 0.42,
      tool_calls: 127,
      ...overrides,
    };
  }

  describe("Session Hook Interface", () => {
    it("should return all session operations", () => {
      const session = useSession();

      expect(session).toHaveProperty("listSessions");
      expect(session).toHaveProperty("loadSession");
      expect(session).toHaveProperty("saveSession");
      expect(session).toHaveProperty("deleteSession");
      expect(typeof session.listSessions).toBe("function");
      expect(typeof session.loadSession).toBe("function");
      expect(typeof session.saveSession).toBe("function");
      expect(typeof session.deleteSession).toBe("function");
    });
  });

  describe("saveSession", () => {
    it("should save session to file with Go-compatible format", async () => {
      const session = createSession({
        id: "test-123",
        name: "My Session",
        cost: 1.23,
        tool_calls: 42,
      });

      await saveSession(session);

      const filePath = join(TEST_SESSION_DIR, "test-123.json");
      const content = await fs.readFile(filePath, "utf-8");
      const saved = JSON.parse(content) as SessionData;

      expect(saved.id).toBe("test-123");
      expect(saved.name).toBe("My Session");
      expect(saved.cost).toBe(1.23);
      expect(saved.tool_calls).toBe(42);
      expect(saved.created_at).toBe(session.created_at);
      // last_used should be updated on save
      expect(new Date(saved.last_used).getTime()).toBeGreaterThanOrEqual(
        new Date(session.last_used).getTime()
      );
    });

    it("should use snake_case field names for Go compatibility", async () => {
      const session = createSession({ id: "test-snake" });
      await saveSession(session);

      const filePath = join(TEST_SESSION_DIR, "test-snake.json");
      const content = await fs.readFile(filePath, "utf-8");

      expect(content).toContain('"created_at"');
      expect(content).toContain('"last_used"');
      expect(content).toContain('"tool_calls"');
      expect(content).not.toContain('"createdAt"');
      expect(content).not.toContain('"lastUsed"');
      expect(content).not.toContain('"toolCalls"');
    });

    it("should update last_used timestamp on save", async () => {
      const session = createSession({
        id: "test-timestamp",
        last_used: "2020-01-01T00:00:00Z",
      });

      await saveSession(session);

      const filePath = join(TEST_SESSION_DIR, "test-timestamp.json");
      const content = await fs.readFile(filePath, "utf-8");
      const saved = JSON.parse(content) as SessionData;

      expect(new Date(saved.last_used).getTime()).toBeGreaterThan(
        new Date("2020-01-01T00:00:00Z").getTime()
      );
    });

    it("should create session directory if it doesn't exist", async () => {
      await fs.rm(TEST_SESSION_DIR, { recursive: true });

      const session = createSession({ id: "test-mkdir" });
      await saveSession(session);

      const filePath = join(TEST_SESSION_DIR, "test-mkdir.json");
      const exists = await fs
        .access(filePath)
        .then(() => true)
        .catch(() => false);

      expect(exists).toBe(true);
    });

    it("should overwrite existing session file", async () => {
      const session = createSession({ id: "test-overwrite", cost: 1.0 });
      await saveSession(session);

      session.cost = 2.5;
      await saveSession(session);

      const loaded = await loadSession("test-overwrite");
      expect(loaded.cost).toBe(2.5);
    });

    it("should handle sessions without optional name field", async () => {
      const session = createSession({ id: "test-no-name", name: undefined });
      await saveSession(session);

      const loaded = await loadSession("test-no-name");
      expect(loaded.name).toBeUndefined();
    });
  });

  describe("loadSession", () => {
    it("should load existing session", async () => {
      const session = createSession({
        id: "test-load",
        name: "Load Test",
        cost: 3.14,
        tool_calls: 256,
      });
      await saveSession(session);

      const loaded = await loadSession("test-load");

      expect(loaded.id).toBe("test-load");
      expect(loaded.name).toBe("Load Test");
      expect(loaded.cost).toBe(3.14);
      expect(loaded.tool_calls).toBe(256);
    });

    it("should throw error for non-existent session", async () => {
      await expect(loadSession("non-existent")).rejects.toThrow(
        "Session not found: non-existent"
      );
    });

    it("should throw error for invalid session format", async () => {
      const filePath = join(TEST_SESSION_DIR, "invalid.json");
      await fs.writeFile(
        filePath,
        JSON.stringify({ id: "invalid" }) // Missing required fields
      );

      await expect(loadSession("invalid")).rejects.toThrow(
        "Invalid session format: invalid"
      );
    });

    it("should validate required fields", async () => {
      const invalidSessions = [
        { created_at: "2020-01-01T00:00:00Z", last_used: "2020-01-01T00:00:00Z", cost: 0, tool_calls: 0 }, // Missing id
        { id: "test", last_used: "2020-01-01T00:00:00Z", cost: 0, tool_calls: 0 }, // Missing created_at
        { id: "test", created_at: "2020-01-01T00:00:00Z", cost: 0, tool_calls: 0 }, // Missing last_used
        { id: "test", created_at: "2020-01-01T00:00:00Z", last_used: "2020-01-01T00:00:00Z", tool_calls: 0 }, // Missing cost
        { id: "test", created_at: "2020-01-01T00:00:00Z", last_used: "2020-01-01T00:00:00Z", cost: 0 }, // Missing tool_calls
      ];

      for (let i = 0; i < invalidSessions.length; i++) {
        const id = `invalid-${i}`;
        const filePath = join(TEST_SESSION_DIR, `${id}.json`);
        await fs.writeFile(filePath, JSON.stringify(invalidSessions[i]));

        await expect(loadSession(id)).rejects.toThrow(
          `Invalid session format: ${id}`
        );
      }
    });

    it("should handle corrupted JSON gracefully", async () => {
      const filePath = join(TEST_SESSION_DIR, "corrupted.json");
      await fs.writeFile(filePath, "{invalid json}");

      await expect(loadSession("corrupted")).rejects.toThrow();
    });
  });

  describe("listSessions", () => {
    it("should return empty array when no sessions exist", async () => {
      const sessions = await listSessions();
      expect(sessions).toEqual([]);
    });

    it("should return all valid sessions", async () => {
      const session1 = createSession({ id: "session-1", name: "First" });
      const session2 = createSession({ id: "session-2", name: "Second" });
      const session3 = createSession({ id: "session-3", name: "Third" });

      await saveSession(session1);
      await saveSession(session2);
      await saveSession(session3);

      const sessions = await listSessions();

      expect(sessions.length).toBe(3);
      expect(sessions.map((s) => s.id)).toContain("session-1");
      expect(sessions.map((s) => s.id)).toContain("session-2");
      expect(sessions.map((s) => s.id)).toContain("session-3");
    });

    it("should sort by last_used descending (most recent first)", async () => {
      const now = Date.now();
      const session1 = createSession({
        id: "oldest",
        last_used: new Date(now - 3000).toISOString(),
      });
      const session2 = createSession({
        id: "newest",
        last_used: new Date(now).toISOString(),
      });
      const session3 = createSession({
        id: "middle",
        last_used: new Date(now - 1000).toISOString(),
      });

      await saveSession(session1);
      await saveSession(session2);
      await saveSession(session3);

      const sessions = await listSessions();

      expect(sessions[0].id).toBe("newest");
      expect(sessions[1].id).toBe("middle");
      expect(sessions[2].id).toBe("oldest");
    });

    it("should skip invalid JSON files gracefully", async () => {
      const validSession = createSession({ id: "valid" });
      await saveSession(validSession);

      // Create invalid files
      await fs.writeFile(join(TEST_SESSION_DIR, "invalid.json"), "{bad json}");
      await fs.writeFile(join(TEST_SESSION_DIR, "missing-fields.json"), "{}");

      const sessions = await listSessions();

      // Should only return valid session
      expect(sessions.length).toBe(1);
      expect(sessions[0].id).toBe("valid");
    });

    it("should skip non-JSON files", async () => {
      const session = createSession({ id: "test" });
      await saveSession(session);

      await fs.writeFile(join(TEST_SESSION_DIR, "readme.txt"), "Not JSON");
      await fs.writeFile(join(TEST_SESSION_DIR, "backup.bak"), "{}");

      const sessions = await listSessions();

      expect(sessions.length).toBe(1);
      expect(sessions[0].id).toBe("test");
